def get_all_codes():
    return ICD10_CODES

def get_code_by_id(code_id):
    for c in ICD10_CODES:
        if c["code"] == code_id:
            return c
    return None

def is_valid_code(code_id):
    return any(c["code"] == code_id for c in ICD10_CODES)

def get_all_keywords():
    """Returns flat list of (code, keyword) pairs for BM25 indexing."""
    rows = []
    for c in ICD10_CODES:
        text = f"{c['code']} {c['description']} {c['category']} {' '.join(c['keywords'])}"
        rows.append(text)
    return rows
